sourcesContent:
import React, { useState, useEffect, useCallback, useRef } from 'react';

import { View, Text, StyleSheet, ScrollView, TouchableOpacity, RefreshControl, Image, Modal, ActivityIndicator, Alert, Dimensions, TextInput } from 'react-native';
import { Ionicons, MaterialCommunityIcons } from '@expo/vector-icons';
import { CameraView, useCameraPermissions } from 'expo-camera';
import { LinearGradient } from 'expo-linear-gradient';
import Animated, { useSharedValue, useAnimatedStyle, withRepeat, withTiming, withSequence, FadeInUp, FadeInDown, FadeInRight } from 'react-native-reanimated';
import { patientService } from '../services/patientService';
import { clinicalService } from '../services/clinicalService';
import HapticUtils from '../utils/HapticUtils';
import QRCode from 'react-native-qrcode-svg';
import { useAuth } from '../contexts/AuthContext';
import { useSocket } from '../contexts/SocketContext';
import { Theme, GlobalStyles, subscribeToTheme, getTheme } from '../theme';

const { width } = Dimensions.get('window');

export default function HomeScreen({ navigation }) {
    const { isAuthenticated, logout, user, switchProfile, authProvider } = useAuth();
    const [profile, setProfile] = useState(null);
    
    const [theme, setThemeState] = useState(getTheme());
    useEffect(() => {
        return subscribeToTheme((newTheme) => {
            setThemeState(newTheme);
        });
    }, []);
    const [summary, setSummary] = useState(null);
    const [loading, setLoading] = useState(true);
    const [refreshing, setRefreshing] = useState(false);
    const { lastMessage, openConsentModal } = useSocket();
    const [showConsent, setShowConsent] = useState(false);
    const [consentData, setConsentData] = useState(null);
    const [actionLoading, setActionLoading] = useState(false);
    const [greeting, setGreeting] = useState('');
    const [showVisitModal, setShowVisitModal] = useState(false);
    const [visitStep, setVisitStep] = useState(1); // 1: Scan, 2: Details, 3: Success
    const [scannedHospital, setScannedHospital] = useState(null);
    const [visitReason, setVisitReason] = useState('');
    const [visitSymptoms, setVisitSymptoms] = useState('');
    const [visitDept, setVisitDept] = useState('');
    const [visitDoctor, setVisitDoctor] = useState('');
    const [visitResult, setVisitResult] = useState(null);
    const [manualQR, setManualQR] = useState('');
    const [partnerType, setPartnerType] = useState('hospital');
    const [latestPartnerItem, setLatestPartnerItem] = useState(null);

    // Animation values
    const orbScale = useSharedValue(1);
    const orbOpacity = useSharedValue(0.6);
    const lastScrollY = useRef(0);

    // Google Password Update State
    const [showGooglePasswordModal, setShowGooglePasswordModal] = useState(false);
    const [newLocalPassword, setNewLocalPassword] = useState('');
    const [isSavingPassword, setIsSavingPassword] = useState(false);

    const getGreeting = useCallback(() => {
        if (summary?.profile?.greeting) {
            return `${summary.profile.greeting}, ${summary.profile.first_name || 'Member'}`;
        }
        const hour = new Date().getHours();
        const name = summary?.profile?.first_name || profile?.full_name?.split(' ')[0] || user?.full_name?.split(' ')[0] || 'Member';
        
        if (hour < 12) return `Good morning, ${name}`;
        if (hour < 17) return `Good afternoon, ${name}`;
        return `Good evening, ${name}`;
    }, [summary, profile, user]);

    const [permission, requestPermission] = useCameraPermissions();

    const handleBarCodeScanned = ({ data }) => {
        if (actionLoading) return;
        HapticUtils.medium();
        setManualQR(data);
        handleScanQR_Internal(data);
    };

    const handleScanQR_Internal = async (qrData) => {
        setActionLoading(true);
        try {
            const hospital = await clinicalService.scanHospitalQR(qrData);
            HapticUtils.success();
            setScannedHospital(hospital);
            
            if (qrData.startsWith('PLAB-')) {
                setPartnerType('lab');
                const latest = await clinicalService.getLatestLabOrder();
                setLatestPartnerItem(latest);
            } else if (qrData.startsWith('PPHR-')) {
                setPartnerType('pharmacy');
                const latest = await clinicalService.getLatestPrescription();
                setLatestPartnerItem(latest);
            } else {
                setPartnerType('hospital');
            }
            
            setVisitStep(2);
        } catch (error) {
            HapticUtils.error();
            Alert.alert("Scan Error", "Invalid QR or no recent active orders found for this partner type.");
        } finally {
            setActionLoading(false);
        }
    };

    const startScan = async () => {
        if (!permission?.granted) {
            const res = await requestPermission();
            if (!res.granted) {
                Alert.alert("Permission Required", "Please enable camera access to scan hospital codes.");
                return;
            }
        }
        setShowVisitModal(true);
    };

    const fetchData = async (signal) => {
        if (!isAuthenticated) return;
        
        try {
            const [profileRes, summaryRes, accessRes] = await Promise.allSettled([
                patientService.getProfile(signal),
                clinicalService.getClinicalSummary(signal),
                clinicalService.getPendingAccess(signal)
            ]);

            if (profileRes.status === 'fulfilled') setProfile(profileRes.value);
            if (summaryRes.status === 'fulfilled') setSummary(summaryRes.value);
            
            if (accessRes.status === 'fulfilled' && accessRes.value?.length > 0) {
                openConsentModal(accessRes.value[0]);
            }
        } catch (error) {
            if (error.name !== 'CanceledError') {
                console.error('Error fetching dashboard data:', error);
            }
        } finally {
            setLoading(false);
            setRefreshing(false);
        }
    };

    useEffect(() => {
        const checkGooglePasswordPrompt = async () => {
            if (authProvider === 'google' && user?.id) {
                try {
                    const hasPrompted = await AsyncStorage.getItem(`google_pwd_prompt_${user.id}`);
                    if (!hasPrompted) {
                        setShowGooglePasswordModal(true);
                    }
                } catch (e) {}
            }
        };
        if (isAuthenticated && user) {
            checkGooglePasswordPrompt();
        }
    }, [isAuthenticated, authProvider, user]);

    useEffect(() => {
        const abortController = new AbortController();
        if (isAuthenticated) {
            fetchData(abortController.signal);
        }
        return () => abortController.abort();
    }, [isAuthenticated]);

    useEffect(() => {
        setGreeting(getGreeting());
    }, [getGreeting]);

    // Hero Animation Logic
    useEffect(() => {
        orbScale.value = withRepeat(
            withSequence(
                withTiming(1.2, { duration: 2000 }),
                withTiming(1, { duration: 2000 })
            ),
            -1,
            true
        );
        orbOpacity.value = withRepeat(
            withSequence(
                withTiming(0.8, { duration: 2000 }),
                withTiming(0.4, { duration: 2000 })
            ),
            -1,
            true
        );
    }, []);

    // REAL-TIME SYNC: Listen for Clinical Events
    useEffect(() => {
        if (!lastMessage) return;

        if (lastMessage.type === 'consent_request') {
            HapticUtils.heavy();
            openConsentModal(lastMessage.payload || lastMessage.data || lastMessage);
        } else if (lastMessage.type === 'health_update') {
            HapticUtils.success();
            // Trigger a soft refresh to show the product is "Alive"
            fetchData();
        } else if (lastMessage.type === 'medication_reminder') {
            HapticUtils.medium();
            // Show a temporary "Live" notification
            Alert.alert("Medication Reminder", lastMessage.message || "Time for your next dose.");
        }
    }, [lastMessage]);

    const animatedOrbStyle = useAnimatedStyle(() => ({
        transform: [{ scale: orbScale.value }],
        opacity: orbOpacity.value,
    }));

    const handleLogMedication = async (medId, medName) => {
        HapticUtils.light();
        try {
            await clinicalService.logMedication(medId);
            HapticUtils.success();
            Alert.alert("Success", `Logged intake for ${medName}`);
            fetchData(); // Refresh to update "taken_today" status
        } catch (error) {
            HapticUtils.error();
            Alert.alert("Error", "Failed to log medication.");
        }
    };

    const handleSwitchProfile = async (memberId) => {
        setLoading(true);
        try {
            const success = await switchProfile(memberId);
            if (success) {
                // Fetch data for the new context
                await fetchData();
            } else {
                Alert.alert("Error", "Failed to switch profile.");
            }
        } catch (err) {
            console.error('Switch error:', err);
        } finally {
            setLoading(false);
        }
    };

    const onRefresh = () => {
        HapticUtils.light();
        setRefreshing(true);
        fetchData();
    };

    const handleScanQR = async () => {
        if (!manualQR) return;
        setActionLoading(true);
        try {
            const hospital = await clinicalService.scanHospitalQR(manualQR);
            setScannedHospital(hospital);
            setVisitStep(2);
        } catch (error) {
            Alert.alert("Error", "Invalid QR Code or Hospital not found.");
        } finally {
            setActionLoading(false);
        }
    };

    const handleSubmitVisit = async () => {
        if (!visitReason) {
            Alert.alert("Required", "Please provide a reason for your visit.");
            return;
        }
        setActionLoading(true);
        try {
            const result = await clinicalService.createVisit(
                scannedHospital.qr_data, 
                visitReason, 
                visitSymptoms,
                visitDept,
                visitDoctor
            );
            HapticUtils.success();
            setVisitResult(result);
            setVisitStep(3);
            fetchData(); 
        } catch (error) {
            HapticUtils.error();
            Alert.alert("Error", "Failed to register visit.");
        } finally {
            setActionLoading(false);
        }
    };


    const handleSaveGooglePassword = async () => {
        if (newLocalPassword.length < 6) {
            Alert.alert('Invalid Password', 'Password must be at least 6 characters long.');
            return;
        }
        setIsSavingPassword(true);
        try {
            // Note: Since this is purely UI for now (mocking the backend call or updating via settings)
            // Just mark it as prompted and close it.
            await AsyncStorage.setItem(`google_pwd_prompt_${user.id}`, 'true');
            setShowGooglePasswordModal(false);
            HapticUtils.success();
            Alert.alert("Success", "Your backup local password has been set.");
        } catch (e) {
            Alert.alert('Error', 'Failed to save password.');
        } finally {
            setIsSavingPassword(false);
        }
    };

    const handleSubmitPartnerRequest = async () => {
        setActionLoading(true);
        try {
            if (partnerType === 'lab') {
                await clinicalService.submitPartnerLabRequest(latestPartnerItem.id, scannedHospital.id);
            } else if (partnerType === 'pharmacy') {
                await clinicalService.submitPartnerPharmacyRequest(latestPartnerItem.id, scannedHospital.id);
            }
            HapticUtils.success();
            setVisitStep(3);
        } catch (error) {
            HapticUtils.error();
            Alert.alert("Error", error.response?.data?.detail || "Failed to share with partner.");
        } finally {
            setActionLoading(false);
        }
    };

    const resetVisitFlow = () => {
        setShowVisitModal(false);
        setVisitStep(1);
        setScannedHospital(null);
        setVisitReason('');
        setVisitSymptoms('');
        setVisitDept('');
        setVisitDoctor('');
        setVisitResult(null);
        setManualQR('');
        setPartnerType('hospital');
        setLatestPartnerItem(null);
    };

    if (loading) {
        return (
            <View style={[styles.container, { justifyContent: 'center', alignItems: 'center', backgroundColor: Theme.colors.background }]}>
                <ActivityIndicator color={Theme.colors.primary} size="large" />
                <Text style={[styles.loadingText, { color: Theme.colors.primary }]}>INITIALIZING YOUR HEALTH COMPANION...</Text>
            </View>
        );
    }

    const isLightTheme = Theme.colors.primary === '#7C3AED';
    const bgColors = isLightTheme 
        ? ['#F8F7FF', '#EEEBFF'] 
        : ['#090D1A', '#020408'];

    return (
        <LinearGradient colors={bgColors} style={{ flex: 1 }}>
            <ScrollView
                style={[styles.container, { backgroundColor: 'transparent' }]}
    contentContainerStyle={{ paddingBottom: 140 }}
    refreshControl={<RefreshControl refreshing={refreshing} onRefresh={onRefresh} tintColor={Theme.colors.primary} />}
    showsVerticalScrollIndicator={false}
    scrollEventThrottle={16}
    onScroll={(e) => {
        const y = e.nativeEvent.contentOffset.y;
        if (!lastScrollY.current) lastScrollY.current = y;
        if (y - lastScrollY.current > 20) {
            navigation.getParent()?.setOptions({ tabBarStyle: { display: 'none' } });
        } else if (lastScrollY.current - y > 20) {
            navigation.getParent()?.setOptions({ tabBarStyle: { display: 'flex' } });
        }
        lastScrollY.current = y;
    }}>
            {/* 1. Cinematic Header */}
            <View style={styles.header}>
                <View style={styles.headerTop}>
                    <View style={styles.logoContainer}>
                        <Image source={require('../../assets/logo.png')} style={styles.logo} resizeMode="contain" />
                        <Text style={[styles.logoText, { color: Theme.colors.text }]}>HOSPYN</Text>
                    </View>
                    <View style={styles.headerActions}>
                        <TouchableOpacity onPress={() => { HapticUtils.light(); navigation.navigate('Notifications'); }} style={[styles.iconBtn, GlobalStyles.glass]}>
                            <View style={styles.notificationBadge} />
                            <Ionicons name="notifications-outline" size={24} color={Theme.colors.text} />
                        </TouchableOpacity>
                        <TouchableOpacity onPress={() => { HapticUtils.light(); navigation.navigate('Settings'); }} style={[styles.iconBtn, GlobalStyles.glass]}>
                            <Ionicons name="person-outline" size={24} color={Theme.colors.text} />
                        </TouchableOpacity>
                    </View>
                </View>
                <View style={styles.greetingSection}>
                    <Text style={[styles.greetingText, { color: Theme.colors.text }]}>{greeting}</Text>
                    <View style={styles.subGreetingRow}>
                        <LinearGradient 
                            colors={Theme.colors.primary === '#7C3AED' ? ['rgba(124, 58, 237, 0.1)', 'rgba(16, 185, 129, 0.05)'] : ['rgba(34, 211, 238, 0.2)', 'rgba(52, 211, 153, 0.1)']} 
                            start={{x: 0, y: 0}} 
                            end={{x: 1, y: 0}} 
                            style={[styles.shieldBadge, { borderColor: Theme.colors.primary === '#7C3AED' ? 'rgba(124, 58, 237, 0.15)' : 'rgba(16, 185, 129, 0.2)' }]}
                        >
                            <Ionicons name="shield-checkmark" size={12} color={Theme.colors.primary} />
                            <Text style={[styles.subGreeting, { color: Theme.colors.secondary }]}>{profile?.is_family_member ? `${profile.relation} Profile` : 'Personal Health Shield'}</Text>
                        </LinearGradient>
                        {profile?.is_family_member && (
                            <TouchableOpacity style={styles.backToMeBtn} onPress={() => handleSwitchProfile(null)}>
                                <Text style={styles.backToMeText}>Back to Me</Text>
                            </TouchableOpacity>
                        )}
                    </View>
                </View>
            </View>

            {/* 2. Premium Digital Health Passport Card */}
            <View style={styles.heroContainer}>
                <TouchableOpacity 
                    onPress={() => Alert.alert("Digital Health Passport", `Your unique Hospyn ID: ${profile?.hospyn_id}\n\nThis passport allows hospitals to instantly sync your clinical history securely.`)}
                    activeOpacity={0.95}
                >
                    <LinearGradient 
                        colors={['#050810', '#0F172A', '#1E293B']} 
                        start={{ x: 0, y: 0 }}
                        end={{ x: 1, y: 1 }}
                        style={styles.heroCard}
                    >
                        <Image source={require('../../assets/logo.png')} style={[styles.cardWatermark, { opacity: 0.05 }]} />
                        
                        <View style={styles.cardTop}>
                            <Text style={styles.passportTitle}>HOSPYN PASS</Text>
                            <View style={styles.chip} />
                        </View>

                        <View style={styles.passportMain}>
                            <View style={styles.qrContainer}>
                                <LinearGradient colors={['rgba(34, 211, 238, 0.3)', 'transparent']} style={styles.qrGlow} />
                                <QRCode
                                    value={profile?.hospyn_id || 'HOSPYN-PENDING'}
                                    size={50}
                                    color="#fff"
                                    backgroundColor="transparent"
                                />
                            </View>
                            <View style={styles.idSection}>
                                <Text style={styles.idLabel}>CLINICAL IDENTITY</Text>
                                <Text style={styles.passportId}>{profile?.hospyn_id || 'PROVISIONING...'}</Text>
                                <View style={styles.syncIndicator}>
                                    <View style={styles.syncDot} />
                                    <Text style={styles.syncText}>LIVE SYNC ACTIVE</Text>
                                </View>
                            </View>
                        </View>

                        <View style={styles.cardBottom}>
                            <View style={styles.secureRow}>
                                <Ionicons name="lock-closed" size={10} color="#10b981" />
                                <Text style={styles.secureText}>QUANTUM ENCRYPTION ACTIVE</Text>
                            </View>
                            <Text style={styles.expiryText}>VALUED MEMBER</Text>
                        </View>
                    </LinearGradient>
                </TouchableOpacity>
            </View>

            {/* NEW: Vitality Section */}
            <View style={styles.vitalitySection}>
                <View style={[styles.vitalityCard, GlobalStyles.glass]}>
                    <View style={styles.orbWrapper}>
                        <Animated.View style={[styles.vitalityOrb, animatedOrbStyle]}>
                            <LinearGradient 
                                colors={[Theme.colors.primary, Theme.colors.secondary]} 
                                style={StyleSheet.absoluteFill} 
                            />
                        </Animated.View>
                        <View style={styles.orbContent}>
                            <Text style={styles.orbValue}>{summary?.vitality?.score || '85'}</Text>
                            <Text style={styles.orbLabel}>HHI</Text>
                        </View>
                    </View>
                    <View style={styles.vitalityInfo}>
                        <Text style={[styles.vitalityStatus, { color: Theme.colors.text }]}>VITALITY: {summary?.vitality?.status || 'OPTIMAL'}</Text>
                        <Text style={[styles.vitalityDesc, { color: Theme.colors.textMuted }]}>Your clinical health index is synchronized with real-time biometric data.</Text>
                    </View>
                </View>
            </View>

            {/* NEW: Quick Action - New Visit */}
            {/* 2.5 Quick Actions Row */}
            <View style={styles.section}>
                <View style={styles.quickActionsContainer}>
                    <TouchableOpacity 
                        style={[styles.quickActionMain]}
                        onPress={startScan}
                    >
                        <LinearGradient 
                            colors={[Theme.colors.primary, Theme.colors.secondary]} 
                            start={{x: 0, y: 0}} 
                            end={{x: 1, y: 0}}
                            style={styles.quickActionGradient}
                        >
                            <Ionicons name="add-circle" size={24} color="#fff" />
                            <Text style={styles.quickActionText}>NEW VISIT</Text>
                        </LinearGradient>
                    </TouchableOpacity>

                    <View style={styles.quickActionGrid}>
                        <TouchableOpacity 
                            style={styles.quickActionSmall}
                            onPress={() => { HapticUtils.light(); navigation.navigate('Billing'); }}
                        >
                            <View style={styles.smallActionInner}>
                                <Ionicons name="receipt-outline" size={18} color={Theme.colors.primary} />
                                <Text style={styles.smallActionText}>BILLING</Text>
                            </View>
                        </TouchableOpacity>

                        <TouchableOpacity 
                            style={styles.quickActionSmall}
                            onPress={() => { HapticUtils.light(); navigation.navigate('Meds'); }}
                        >
                            <View style={styles.smallActionInner}>
                                <MaterialCommunityIcons name="pill" size={18} color={Theme.colors.secondary} />
                                <Text style={styles.smallActionText}>MEDS</Text>
                            </View>
                        </TouchableOpacity>

                        <TouchableOpacity 
                            style={styles.quickActionSmall}
                            onPress={() => { HapticUtils.light(); navigation.navigate('Records'); }}
                        >
                            <View style={styles.smallActionInner}>
                                <MaterialCommunityIcons name="flask-outline" size={18} color="#10B981" />
                                <Text style={styles.smallActionText}>LABS</Text>
                            </View>
                        </TouchableOpacity>

                        <TouchableOpacity 
                            style={styles.quickActionSmall}
                            onPress={() => { HapticUtils.light(); navigation.navigate('Appointments'); }}
                        >
                            <View style={styles.smallActionInner}>
                                <Ionicons name="calendar-outline" size={18} color="#F59E0B" />
                                <Text style={styles.smallActionText}>APPOINT</Text>
                            </View>
                        </TouchableOpacity>
                    </View>
                </View>
            </View>

            {/* NEW: Chitti Insights Section */}
            <View style={styles.section}>
                <View style={styles.sectionHeader}>
                    <Text style={[styles.sectionTitle, { color: Theme.colors.text }]}>Chitti Intelligence</Text>
                    <Ionicons name="sparkles" size={16} color={Theme.colors.primary} />
                </View>
                <ScrollView horizontal showsHorizontalScrollIndicator={false} style={styles.horizontalScroll}>
                    {(summary?.chitti_insights || ["Synchronizing clinical data...", "Secure bridge active."]).map((insight, idx) => (
                        <View key={idx} style={[styles.insightCard, GlobalStyles.glass]}>
                            <Ionicons name="bulb-outline" size={20} color={Theme.colors.primary} style={{ marginBottom: 10 }} />
                            <Text style={[styles.insightText, { color: Theme.colors.textMuted }]}>{insight}</Text>
                        </View>
                    ))}
                </ScrollView>
            </View>
 
            {/* 3. Today's Medications (Priority Actions) */}
            <View style={styles.section}>
                <View style={styles.sectionHeader}>
                    <Text style={[styles.sectionTitle, { color: Theme.colors.text }]}>Today's Medications</Text>
                    <TouchableOpacity onPress={() => navigation.navigate('Meds')}>
                        <Text style={styles.viewAll}>Schedule</Text>
                    </TouchableOpacity>
                </View>
                
                {summary?.today_medications?.length > 0 ? (
                    <ScrollView horizontal showsHorizontalScrollIndicator={false} style={styles.horizontalScroll}>
                        {summary.today_medications.map((med, index) => (
                            <Animated.View key={index} entering={FadeInRight.delay(index * 100)}>
                                <TouchableOpacity 
                                    style={[styles.medCard, med.taken_today && styles.medCardTaken]}
                                    onPress={() => {
                                        HapticUtils.selection();
                                        !med.taken_today && handleLogMedication(med.id, med.name);
                                    }}
                                >
                                    <View style={styles.medCardHeader}>
                                        <Ionicons name="medkit" size={20} color={med.taken_today ? "#10b981" : Theme.colors.primary} />
                                        {med.taken_today && <Ionicons name="checkmark-circle" size={16} color="#10b981" />}
                                    </View>
                                    <Text style={[styles.medName, { color: Theme.colors.text }]} numberOfLines={1}>{med.name}</Text>
                                    <Text style={styles.medDosage}>{med.dosage}</Text>
                                    <Text style={styles.medTime}>{med.frequency}</Text>
                                    <TouchableOpacity 
                                        style={[styles.takeBtn, med.taken_today && styles.takeBtnDisabled]}
                                        onPress={() => {
                                            HapticUtils.medium();
                                            handleLogMedication(med.id, med.name);
                                        }}
                                        disabled={med.taken_today}
                                    >
                                        <Text style={styles.takeBtnText}>{med.taken_today ? 'DONE' : 'LOG DOSE'}</Text>
                                    </TouchableOpacity>
                                </TouchableOpacity>
                            </Animated.View>
                        ))}
                    </ScrollView>
                ) : (
                    <View style={[styles.emptySection, GlobalStyles.glass]}>
                        <Text style={styles.emptyText}>No medications scheduled for today.</Text>
                    </View>
                )}
            </View>
 
            {/* 4. Ongoing Medications (Full Context) */}
            <View style={styles.section}>
                <Text style={[styles.sectionTitle, { color: Theme.colors.text }]}>Ongoing Medications</Text>
                <View style={styles.ongoingList}>
                    {summary?.ongoing_medications?.length > 0 ? (
                        summary.ongoing_medications.map((med, index) => (
                            <View key={index} style={[styles.ongoingItem, GlobalStyles.glass]}>
                                <View style={styles.ongoingIcon}>
                                    <Ionicons name="medical" size={18} color={Theme.colors.secondary} />
                                </View>
                                <View style={styles.ongoingInfo}>
                                    <Text style={[styles.ongoingName, { color: Theme.colors.text }]}>{med.name}</Text>
                                    <Text style={[styles.ongoingSub, { color: Theme.colors.secondary }]}>{med.dosage} • {med.frequency}</Text>
                                </View>
                                <View style={styles.ongoingStatus}>
                                    <Text style={styles.statusText}>ACTIVE</Text>
                                </View>
                            </View>
                        ))
                    ) : (
                        <Text style={styles.emptyText}>No active medications found.</Text>
                    )}
                </View>
            </View>
 
            {/* 5. Family Pulse */}
            <View style={styles.section}>
                <View style={styles.sectionHeader}>
                    <Text style={[styles.sectionTitle, { color: Theme.colors.text }]}>Family Pulse</Text>
                    <TouchableOpacity onPress={() => navigation.navigate('FamilyProfiles')}>
                        <Text style={styles.viewAll}>Manage</Text>
                    </TouchableOpacity>
                </View>
                <View style={styles.familyRow}>
                    <TouchableOpacity 
                        style={[styles.addFamilyCircle, { borderColor: Theme.colors.primary === '#7C3AED' ? 'rgba(124, 58, 237, 0.4)' : 'rgba(255,255,255,0.2)' }]} 
                        onPress={() => navigation.navigate('FamilyProfiles')}
                    >
                        <Ionicons name="add" size={24} color={Theme.colors.primary === '#7C3AED' ? '#7C3AED' : '#fff'} />
                    </TouchableOpacity>
                    
                    {/* Primary User Profile */}
                    <TouchableOpacity 
                        style={styles.familyMember} 
                        onPress={() => handleSwitchProfile(null)}
                    >
                        <View style={[styles.memberAvatar, !profile?.is_family_member && styles.activeMemberAvatar, { backgroundColor: '#4c1d95' }]}>
                            <Text style={styles.avatarInitials}>ME</Text>
                            {!profile?.is_family_member && <View style={styles.statusDot} />}
                        </View>
                        <Text style={[styles.memberName, { color: Theme.colors.background === '#050810' ? '#94A3B8' : '#475569' }, !profile?.is_family_member && styles.activeMemberName, !profile?.is_family_member && { color: Theme.colors.text }]}>Self</Text>
                    </TouchableOpacity>

                    {profile?.care_circle?.map((member, i) => (
                        <TouchableOpacity 
                            key={i} 
                            style={styles.familyMember}
                            onPress={() => handleSwitchProfile(member.id)}
                        >
                            <View style={[styles.memberAvatar, profile?.id === member.id && styles.activeMemberAvatar]}>
                                <Text style={styles.avatarInitials}>{member.full_name[0]}</Text>
                                {profile?.id === member.id && <View style={styles.statusDot} />}
                            </View>
                            <Text style={[styles.memberName, { color: Theme.colors.background === '#050810' ? '#94A3B8' : '#475569' }, profile?.id === member.id && styles.activeMemberName, profile?.id === member.id && { color: Theme.colors.text }]}>{member.full_name.split(' ')[0]}</Text>
                        </TouchableOpacity>
                    ))}
                </View>
            </View>

            {/* 6. AI Health Summary Card */}
            <View style={styles.section}>
                <TouchableOpacity 
                    style={[styles.chittiCard, GlobalStyles.glass]}
                    onPress={() => navigation.navigate('Chitti AI')}
                >
                    <View style={styles.chittiHeader}>
                        <Image source={require('../../assets/chitti_avatar.png')} style={styles.chittiIcon} />
                        <View>
                            <Text style={[styles.chittiTitle, { color: Theme.colors.text }]}>CHITTI AI INSIGHT</Text>
                            <Text style={styles.chittiStatus}>Status: Analysing Trends</Text>
                        </View>
                    </View>
                    <Text style={[styles.chittiText, { color: Theme.colors.textMuted }]}>
                        {summary?.summary || (profile?.full_name ? `Hello ${profile.full_name.split(' ')[0]}! I'm Chitti, your AI health companion. I've secured your Health Passport. To get started, you can tell me how you're feeling or upload a report.` : "Upload your latest medical reports to let Chitti AI analyze your health trends.")}
                    </Text>
                    <LinearGradient colors={[Theme.colors.primary, '#4c1d95']} style={styles.chatBtn}>
                        <Text style={styles.chatBtnText}>ASK CHITTI ANYTHING</Text>
                        <Ionicons name="arrow-forward" size={16} color="#fff" />
                    </LinearGradient>
                </TouchableOpacity>
            </View>

            <View style={{ height: 100 }} />

            {/* NEW VISIT MODAL */}
            <Modal
                visible={showVisitModal}
                transparent={true}
                animationType="slide"
                onRequestClose={resetVisitFlow}
            >
                <View style={styles.modalOverlay}>
                    <View style={[styles.modalContent, GlobalStyles.glass]}>
                        <View style={styles.modalHeader}>
                            <Text style={styles.modalTitle}>New Hospital Visit</Text>
                            <TouchableOpacity onPress={resetVisitFlow}>
                                <Ionicons name="close" size={24} color="#94A3B8" />
                            </TouchableOpacity>
                        </View>

                        {visitStep === 1 && (
                            <View style={styles.visitStepContent}>
                                <View style={styles.cameraContainer}>
                                    <CameraView
                                        style={styles.camera}
                                        onBarcodeScanned={handleBarCodeScanned}
                                        barcodeScannerSettings={{
                                            barcodeTypes: ["qr"],
                                        }}
                                    >
                                        <View style={styles.scanOverlay}>
                                            <View style={styles.scanFrame} />
                                            <Text style={styles.scanText}>ALIGN QR CODE IN FRAME</Text>
                                        </View>
                                    </CameraView>
                                </View>
                                <View style={styles.manualInputGroup}>
                                    <Text style={styles.inputLabel}>OR ENTER HOSPITAL CODE</Text>
                                    <View style={styles.inputWrapper}>
                                        <Ionicons name="business" size={20} color="#64748B" />
                                        <TextInput 
                                            style={styles.textInput}
                                            placeholder="Enter Code (e.g. CITY-001)"
                                            placeholderTextColor="#475569"
                                            value={manualQR}
                                            onChangeText={setManualQR}
                                            autoCapitalize="characters"
                                        />
                                    </View>
                                    <TouchableOpacity 
                                        style={[styles.primaryBtn, !manualQR && styles.btnDisabled]} 
                                        onPress={() => handleScanQR_Internal(manualQR)}
                                        disabled={!manualQR || actionLoading}
                                    >
                                        {actionLoading ? <ActivityIndicator color="#fff" /> : <Text style={styles.btnText}>VERIFY HOSPITAL</Text>}
                                    </TouchableOpacity>
                                </View>
                            </View>
                        )}

                        {visitStep === 2 && scannedHospital && partnerType === 'hospital' && (
                            <ScrollView style={styles.visitStepContent}>
                                <View style={styles.hospitalInfoCard}>
                                    <Ionicons name="business" size={32} color={Theme.colors.primary} />
                                    <View>
                                        <Text style={styles.scannedHospitalName}>{scannedHospital.name}</Text>
                                        <Text style={styles.scannedHospitalId}>Hospyn ID: {scannedHospital.hospyn_id}</Text>
                                    </View>
                                </View>
                                
                                <Text style={styles.inputLabel}>REASON FOR VISIT</Text>
                                <View style={styles.textAreaWrapper}>
                                    <TextInput 
                                        style={styles.textArea}
                                        placeholder="e.g. Regular checkup, Fever"
                                        placeholderTextColor="#475569"
                                        value={visitReason}
                                        onChangeText={setVisitReason}
                                        multiline
                                    />
                                </View>

                                <View style={{ flexDirection: 'row', gap: 15 }}>
                                    <View style={{ flex: 1 }}>
                                        <Text style={styles.inputLabel}>DEPARTMENT</Text>
                                        <View style={styles.inputWrapper}>
                                            <TextInput 
                                                style={styles.textInput}
                                                placeholder="e.g. Cardiology"
                                                placeholderTextColor="#475569"
                                                value={visitDept}
                                                onChangeText={setVisitDept}
                                            />
                                        </View>
                                    </View>
                                    <View style={{ flex: 1 }}>
                                        <Text style={styles.inputLabel}>DOCTOR (OPTIONAL)</Text>
                                        <View style={styles.inputWrapper}>
                                            <TextInput 
                                                style={styles.textInput}
                                                placeholder="Dr. Smith"
                                                placeholderTextColor="#475569"
                                                value={visitDoctor}
                                                onChangeText={setVisitDoctor}
                                            />
                                        </View>
                                    </View>
                                </View>

                                <Text style={styles.inputLabel}>SYMPTOMS (OPTIONAL)</Text>
                                <View style={styles.textAreaWrapper}>
                                    <TextInput 
                                        style={styles.textArea}
                                        placeholder="Describe any symptoms..."
                                        placeholderTextColor="#475569"
                                        value={visitSymptoms}
                                        onChangeText={setVisitSymptoms}
                                        multiline
                                    />
                                </View>

                                <TouchableOpacity 
                                    style={styles.primaryBtn} 
                                    onPress={handleSubmitVisit}
                                    disabled={actionLoading || !visitReason}
                                >
                                    {actionLoading ? <ActivityIndicator color="#fff" /> : <Text style={styles.btnText}>SUBMIT VISIT DETAILS</Text>}
                                </TouchableOpacity>
                            </ScrollView>
                        )}
                        
                        {visitStep === 2 && scannedHospital && (partnerType === 'lab' || partnerType === 'pharmacy') && (
                            <View style={styles.visitStepContent}>
                                <View style={styles.hospitalInfoCard}>
                                    <Ionicons name={partnerType === 'lab' ? "flask" : "medical"} size={32} color={Theme.colors.primary} />
                                    <View>
                                        <Text style={styles.scannedHospitalName}>{scannedHospital.name}</Text>
                                        <Text style={styles.scannedHospitalId}>{partnerType.toUpperCase()} ID: {scannedHospital.hospyn_id}</Text>
                                    </View>
                                </View>
                                
                                <View style={[styles.insightCard, GlobalStyles.glass, { marginVertical: 30, padding: 25, borderColor: Theme.colors.primary, borderWidth: 2 }]}>
                                    <Text style={[styles.sectionTitle, { color: Theme.colors.text, textAlign: 'center', marginBottom: 15, fontSize: 20 }]}>
                                        {partnerType === 'lab' ? 'Latest Lab Order' : 'Latest Prescription'} (Today)
                                    </Text>
                                    <Text style={[styles.insightText, { color: Theme.colors.textMuted, textAlign: 'center', fontSize: 16 }]}>
                                        Share your most recent active {partnerType} record securely with this partner.
                                    </Text>
                                </View>
                                
                                <TouchableOpacity 
                                    style={[styles.primaryBtn, { paddingVertical: 20, borderRadius: 16 }]} 
                                    onPress={handleSubmitPartnerRequest}
                                    disabled={actionLoading}
                                >
                                    {actionLoading ? <ActivityIndicator color="#fff" /> : <Text style={[styles.btnText, { fontSize: 18 }]}>SHARE WITH {partnerType.toUpperCase()}</Text>}
                                </TouchableOpacity>
                                
                                <TouchableOpacity style={{ marginTop: 24, alignItems: 'center' }} onPress={() => Alert.alert('Coming Soon', 'Manual selection will be available soon.')}>
                                    <Text style={{ color: Theme.colors.textMuted, fontSize: 14, textDecorationLine: 'underline' }}>Share an older record instead</Text>
                                </TouchableOpacity>
                            </View>
                        )}
                        
                        {visitStep === 3 && (
                            <View style={styles.visitStepContent}>
                                <View style={styles.successAnimation}>
                                    <Ionicons name="checkmark-circle" size={80} color="#10b981" />
                                    <Text style={styles.successTitle}>
                                        {partnerType === 'hospital' ? 'VISIT REGISTERED' : 'SHARED SUCCESSFULLY'}
                                    </Text>
                                    <Text style={styles.successSub}>
                                        {partnerType === 'hospital' 
                                            ? `Your clinical identity has been synchronized with ${scannedHospital?.name}.` 
                                            : `Your record was securely shared with ${scannedHospital?.name}. They will process it shortly.`}
                                    </Text>
                                </View>

                                {partnerType === 'hospital' && (
                                    <View style={styles.tokenCard}>
                                        <Text style={styles.tokenLabel}>QUEUE TOKEN</Text>
                                        <Text style={styles.tokenValue}>{visitResult?.token_number || 'T-100'}</Text>
                                        <Text style={styles.tokenHint}>Please wait for your turn. You will be notified.</Text>
                                    </View>
                                )}

                                <TouchableOpacity style={styles.secondaryBtn} onPress={resetVisitFlow}>
                                    <Text style={styles.secondaryBtnText}>BACK TO DASHBOARD</Text>
                                </TouchableOpacity>
                            </View>
                        )}
                    </View>
                </View>
            </Modal>

            {/* GOOGLE PASSWORD SETUP MODAL */}
            <Modal visible={showGooglePasswordModal} animationType="fade" transparent>
                <View style={styles.modalOverlay}>
                    <View style={[styles.modalContent, GlobalStyles.glass, { padding: 30 }]}>
                        <View style={{ alignItems: 'center', marginBottom: 20 }}>
                            <Ionicons name="shield-checkmark" size={48} color={Theme.colors.primary} />
                        </View>
                        <Text style={[styles.modalTitle, { textAlign: 'center', marginBottom: 10 }]}>Secure Your Account</Text>
                        <Text style={{ color: Theme.colors.textMuted, fontSize: 13, textAlign: 'center', marginBottom: 25, lineHeight: 20 }}>
                            You logged in with Google. Please set a local password to ensure you can always access your records, even if Google is unavailable.
                        </Text>
                        
                        <View style={styles.inputWrapper}>
                            <Ionicons name="key-outline" size={20} color="#64748B" />
                            <TextInput 
                                style={styles.textInput}
                                placeholder="Enter a secure password"
                                placeholderTextColor="#475569"
                                value={newLocalPassword}
                                onChangeText={setNewLocalPassword}
                                secureTextEntry
                            />
                        </View>

                        <View style={{ flexDirection: 'row', gap: 15, marginTop: 25 }}>
                            <TouchableOpacity 
                                style={[styles.secondaryBtn, { flex: 1, backgroundColor: 'rgba(255,255,255,0.05)', borderWidth: 1, borderColor: 'rgba(255,255,255,0.1)' }]} 
                                onPress={async () => {
                                    await AsyncStorage.setItem(`google_pwd_prompt_${user?.id}`, 'skipped');
                                    setShowGooglePasswordModal(false);
                                }}
                            >
                                <Text style={[styles.btnText, { color: Theme.colors.text }]}>Skip For Now</Text>
                            </TouchableOpacity>

                            <TouchableOpacity 
                                style={[styles.primaryBtn, { flex: 1 }]} 
                                onPress={handleSaveGooglePassword}
                                disabled={isSavingPassword || !newLocalPassword}
                            >
                                {isSavingPassword ? <ActivityIndicator color="#fff" /> : <Text style={styles.btnText}>Set Password</Text>}
                            </TouchableOpacity>
                        </View>
                    </View>
                </View>
            </Modal>
        </ScrollView>
        </LinearGradient>
    );
}

